// Initialize game state on first frame
if (!state.initialized) {
  state.score = 0;
  state.lives = 3;
  state.gameOver = false;
  state.initialized = true;
}

// Player movement - responds to arrow key presses
const MOVE_DIST = 20;
const MAX_X = 400;
const MIN_X = -400;
const MAX_Y = 280;
const MIN_Y = -280;

if (Input.isKeyPressed("ArrowUp")) {
  self.y -= MOVE_DIST;
}
if (Input.isKeyPressed("ArrowDown")) {
  self.y += MOVE_DIST;
}
if (Input.isKeyPressed("ArrowLeft")) {
  self.x -= MOVE_DIST;
}
if (Input.isKeyPressed("ArrowRight")) {
  self.x += MOVE_DIST;
}

// Bounds checking
if (self.x > MAX_X) self.x = MAX_X;
if (self.x < MIN_X) self.x = MIN_X;
if (self.y > MAX_Y) self.y = MAX_Y;
if (self.y < MIN_Y) self.y = MIN_Y;

// Check collision with all cars
const carNames = ['Car_R1_1', 'Car_R1_2', 'Car_R1_3', 
                   'Car_R2_1', 'Car_R2_2', 'Car_R2_3',
                   'Car_R3_1', 'Car_R3_2', 'Car_R3_3',
                   'Car_R4_1', 'Car_R4_2', 'Car_R4_3',
                   'Car_R5_1', 'Car_R5_2', 'Car_R5_3'];

let hitCar = false;
for (let carName of carNames) {
  let car = entities.get(carName);
  if (car) {
    // AABB collision: abs(dx) < 35 && abs(dy) < 25
    let dx = Math.abs(self.x - car.x);
    let dy = Math.abs(self.y - car.y);
    if (dx < 35 && dy < 25) {
      hitCar = true;
      break;
    }
  }
}

// Handle collision
if (hitCar) {
  state.lives -= 1;
  self.x = 0;
  self.y = 260;
  if (state.lives <= 0) {
    state.gameOver = true;
  }
}

// Check win condition
if (self.y < -260) {
  state.score += 1;
  self.x = 0;
  self.y = 260;
}

// Row 1: Red cars moving left
const SPEED = -150;
self.x += SPEED * dt;

// Wrap around
if (self.x > 420) self.x = -420;
if (self.x < -420) self.x = 420;

